import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager {
  static const _authTokenKey = 'auth-token';
  static const _userDataKey = 'user-data';

  Future<void> login(String username, String password) async {
    // Implement your own authentication logic here
    final authToken = await authenticateUser(username, password);
    if (authToken != null) {
      SharedPreferences.getInstance().then((preferences) {
        preferences.setString(_authTokenKey, authToken);
        preferences.setString(_userDataKey, jsonEncode({'username': username}));
      });
    }
  }

  Future<void> logout() async {
    SharedPreferences.getInstance().then((preferences) {
      preferences.remove(_authTokenKey);
      preferences.remove(_userDataKey);
    });
  }

  bool isLoggedIn() {
    return SharedPreferences.getInstance().then((preferences) => preferences.getString(_authTokenKey) != null);
  }

  Future<String> getAuthToken() async {
    return SharedPreferences.getInstance().then((preferences) => preferences.getString(_authTokenKey));
  }

  Future<Map<String, dynamic>> getUserData() async {
    return SharedPreferences.getInstance().then((preferences) => jsonDecode(preferences.getString(_userDataKey)));
  }
}